SELECT f.id, f.user_id AS userId, f.content, f.reply, f.status, f.create_time AS createTime, f.update_time AS updateTime, u.nickname AS userNickName FROM feedback f LEFT JOIN system_users u ON f.user_id = u.id WHERE f.deleted = 0
AND u.nickname LIKE CONCAT('%', #{reqVO.userNickName}, '%')
AND f.content LIKE CONCAT('%', #{reqVO.content}, '%')
AND f.status = #{reqVO.status}
AND f.create_time BETWEEN #{reqVO.createTime[0]} AND #{reqVO.createTime[1]}
AND f.update_time BETWEEN #{reqVO.updateTime[0]} AND #{reqVO.updateTime[1]}
ORDER BY f.create_time DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM feedback f
LEFT JOIN system_users u ON f.user_id = u.id
WHERE f.deleted = 0

    AND u.nickname LIKE CONCAT('%', #{reqVO.userNickName}, '%')


    AND f.content LIKE CONCAT('%', #{reqVO.content}, '%')


    AND f.status = #{reqVO.status}


    AND f.create_time BETWEEN #{reqVO.createTime[0]} AND #{reqVO.createTime[1]}


    AND f.update_time BETWEEN #{reqVO.updateTime[0]} AND #{reqVO.updateTime[1]}

SELECT f.id, f.user_id AS userId, f.content, f.reply, f.status, f.create_time AS createTime, f.update_time AS updateTime, u.nickname AS userNickName FROM feedback f LEFT JOIN system_users u ON f.user_id = u.id WHERE f.deleted = 0
AND u.nickname LIKE CONCAT('%', #{reqVO.userNickName}, '%')
AND f.content LIKE CONCAT('%', #{reqVO.content}, '%')
AND f.status = #{reqVO.status}
AND f.create_time BETWEEN #{reqVO.createTime[0]} AND #{reqVO.createTime[1]}
AND f.update_time BETWEEN #{reqVO.updateTime[0]} AND #{reqVO.updateTime[1]}
ORDER BY f.create_time DESC
